            }
            function lock() { merge(); clearLines(); spawn(); }
            function move(d) { if (over || paused) return; if (!collide(piece.x + d, piece.y, piece.m)) { piece.x += d; api.sound.move(); draw(); } }
            function rotate() {
                if (over || paused) return;
