            var sx = 0, sy = 0, st = 0, moved = false;
            function ts_(e) { var t = e.touches[0]; sx = t.clientX; sy = t.clientY; st = Date.now(); moved = false; }
            function tm_(e) {
                var t = e.touches[0], dx = t.clientX - sx, dy = t.clientY - sy;
